const u = $input.first().json;
let chatId, text, firstName;

if (u.callback_query) {
  chatId    = String(u.callback_query.message.chat.id);
  text      = u.callback_query.data;
  firstName = u.callback_query.from.first_name || 'there';
} else if (u.message) {
  chatId    = String(u.message.chat.id);
  text      = u.message.text || '';
  firstName = u.message.from.first_name || 'there';
} else {
  return [];
}

return [{ json: { chatId, text: text.trim(), firstName, sessionKey: chatId } }];

const output = $input.first().json.output || '';
const chatId = $('Extract Message').first().json.chatId;

if (!output || output.trim() === '') {
  return [{ json: { chatId, text: "✅ Done! Is there anything else I can help you with? Type /start to see the main menu." } }];
}

return [{ json: { chatId, text: output } }];
